class TestCreateDir:
    """Tests for create_dir."""

    def test_create_dir(self):
        """Directory is created."""
        with tempfile.TemporaryDirectory() as tmpdir:
            path = os.path.join(tmpdir, 'newdir')
            create_dir(path)
            assert os.path.isdir(path)

    def test_create_dir_nested(self):
        """Nested directories are created."""
        with tempfile.TemporaryDirectory() as tmpdir:
            path = os.path.join(tmpdir, 'a', 'b', 'c')
            create_dir(path)
            assert os.path.isdir(path)

    def test_create_dir_already_exists(self):
        """Does not fail if directory exists."""
        with tempfile.TemporaryDirectory() as tmpdir:
            create_dir(tmpdir)  # Should not raise

    def test_create_dir_permission_error(self):
        """PermissionError is raised for unwritable locations."""
        try:
            create_dir('/root/impossible_autojump_test')
        except PermissionError:
            pass
        else:
            # Not running as restricted user, skip
            pass


